-- =============================================================================
-- DEVELOPMENT SEED DATA
-- Run this in the Supabase SQL editor (it bypasses RLS since the editor
-- runs as postgres / service role).
--
-- ORDER:
--   1. Run 001_initial_schema.sql
--   2. Run 002_rls.sql
--   3. Create auth users in Supabase Auth dashboard (Authentication → Users)
--   4. Run this file — it will upsert users and insert all project data
-- =============================================================================

-- Disable triggers temporarily so we can insert users directly
-- (The trigger inserts into public.users on auth.users INSERT,
--  but we're seeding public.users directly here)

-- ─── STEP 1: Set admin roles ────────────────────────────────────────────────
-- 1. Create your auth accounts in Supabase Auth → Users → Add user
-- 2. Sign in to the app at least once — this auto-creates your public.users row
--    (role defaults to 'team_member')
-- 3. Then run this to promote to admin:

UPDATE public.users
SET role = 'admin'
WHERE email IN ('demian@oaki.studio', 'diego@oaki.studio');


-- ─── STEP 2: Clients ─────────────────────────────────────────────────────────

ON CONFLICT (id) DO NOTHING;


-- ─── STEP 3: Projects ────────────────────────────────────────────────────────

ON CONFLICT (id) DO NOTHING;


-- ─── STEP 4: Delivery rounds ─────────────────────────────────────────────────

ON CONFLICT (id) DO NOTHING;


-- ─── STEP 5: Project views ───────────────────────────────────────────────────

-- Project 1 — 6 views
ON CONFLICT (id) DO NOTHING;

-- Project 2 — 4 views
ON CONFLICT (id) DO NOTHING;

-- Project 3 — 3 views
ON CONFLICT (id) DO NOTHING;


-- ─── STEP 6: View stage states ───────────────────────────────────────────────

-- Project 1 / Round 0 — mixed progress
ON CONFLICT (delivery_round_id, project_view_id, stage) DO NOTHING;

-- Project 2 / Round 0 — all not_started
ON CONFLICT (delivery_round_id, project_view_id, stage) DO NOTHING;

-- Project 3 / Round 1 — revision, all not_started
ON CONFLICT (delivery_round_id, project_view_id, stage) DO NOTHING;
